import base64
import os

FILES = {
    "src/lib/appointmentEmails.ts": """""",
}

def main():
    repo_root = os.getcwd()
    for rel_path, b64content in FILES.items():
        full_path = os.path.join(repo_root, rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        content = base64.b64decode(b64content)
        with open(full_path, 'wb') as f:
            f.write(content)
        print(f'Wrote {rel_path} ({len(content)} bytes)')
    print('Done. Now run: git add -A && git commit -m "fix: whatsapp review request blocked when client has no email" && git push')

if __name__ == '__main__':
    main()